                                local v = Instance.new('Part')
                                v.CanCollide = false
                                for name, prop in getproperties(part:WaitForChild('Handle')) do
                                    pcall(function()
                                        v[name] = prop
                                    end)
                                end
                                part.Handle.Transparency = 1
                                v.Anchored = true
                                v.Material = Enum.Material.Neon
                                for _, child in part.Handle:GetChildren() do
                                    child.Parent = v
                                end
                                table.insert(Decoys, {
                                    TP = part.Handle,
